const express = require('express');
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/dataquery', { useNewUrlParser: true, useUnifiedTopology: true });

// Define the schema for the collection
const dataSchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});

// Create a model from the schema
const Data = mongoose.model('Data', dataSchema);

// Express app setup
const app = express();
app.use(express.json());

// API endpoint to query data
app.post('/query', async (req, res) => {
  try {
    // Get search filters from request body
    const filters = req.body;

    // Validate and sanitize input
    if (!filters || typeof filters !== 'object') {
      return res.status(400).json({ error: 'Invalid query parameters' });
    }

    // Pass filters directly to MongoDB find() operation
    const result = await Data.find(filters);

    // Return the result
    res.json(result);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});